const items = $input.all();
const chatId = $('ТГ: Входящие').item.json.message?.chat?.id 
  || $('ТГ: Входящие').item.json.callback_query?.message?.chat?.id 
  || $('ТГ: Входящие').item.json.callback_query?.from?.id;

if (items.length === 0 || !items[0].json.id) {
  return [{ json: { payload: JSON.stringify({
    chat_id: chatId,
    text: "У тебя пока нет агентов. Создай агента в ElevenLabs и напиши /agents снова."
  }) } }];
}

const buttons = items.map(item => ([{
  text: item.json.agent_name,
  callback_data: `select_agent_${item.json.id}`
}]));

return [{ json: { payload: JSON.stringify({
  chat_id: chatId,
  text: "Твои агенты:",
  reply_markup: { inline_keyboard: buttons }
}) } }];

