const pendingAction = $('БД: Получить состояние').item.json.pending_action;
const actionMap = {
  prompt: 'update_prompt',
  welcome: 'update_welcome',
  kb: 'update_kb'
};

return [{
  json: {
    action: actionMap[pendingAction] || 'update_prompt',
    value: $('ТГ: Входящие').item.json.message.text,
    elevenlabs_agent_id: $('БД: Получить состояние').item.json.elevenlabs_agent_id,
    agent_name: $('БД: Получить состояние').item.json.agent_name,
    knowledge_base_id: $('БД: Получить состояние').item.json.knowledge_base_id,
    agent_db_id: $('БД: Получить состояние').item.json.current_agent_id
  }
}];

const agentDbId = $('Код: Парсинг LLM').item.json.agent_db_id;
const agentName = $('Код: Парсинг LLM').item.json.agent_name || `Агент #${agentDbId}`;
const elData = $input.item.json;
const prompt = elData.conversation_config?.agent?.prompt?.prompt || '—';
const firstMessage = elData.conversation_config?.agent?.first_message || '—';

const kbList = elData.conversation_config?.agent?.prompt?.knowledge_base;
const kb = kbList && kbList.length > 0
  ? ($('Код: Парсинг LLM').item.json.action === 'update_kb'
      ? $('Код: Парсинг LLM').item.json.value
      : kbList[0].name)
  : '❌ Нет';

const payload = {
  chat_id: $('ТГ: Входящие').item.json.message.chat.id,
  text: `Агент: ${agentName}\n\n📝 Промпт: ${prompt}\n👋 Приветствие: ${firstMessage}\n📚 База знаний: ${kb}\n\nЧто хочешь изменить?`,
  reply_markup: {
    inline_keyboard: [
      [{ text: "📝 Промпт", callback_data: `action_prompt_${agentDbId}` }],
      [{ text: "👋 Приветствие", callback_data: `action_welcome_${agentDbId}` }],
      [{ text: "📚 База знаний", callback_data: `action_kb_${agentDbId}` }],
      [{ text: "⬅️ Назад к агентам", callback_data: "back_to_agents" }]
    ]
  }
};

return [{ json: { payload: JSON.stringify(payload) } }];

