const telegramId = $('ТГ: Входящие').item.json.message.from.id;
const agents = $input.item.json.agents || [];

const escape = s => String(s).replace(/'/g, "''");
const userSubquery = `(SELECT id FROM users WHERE telegram_id = ${Number(telegramId)})`;

let deleteQuery = `DELETE FROM agents WHERE user_id = ${userSubquery}`;

if (agents.length > 0) {
  const ids = agents.map(a => `'${escape(a.agent_id)}'`).join(', ');
  deleteQuery += ` AND elevenlabs_agent_id NOT IN (${ids})`;
}

let upsertQuery = null;
if (agents.length > 0) {
  const rows = agents.map(a =>
    `(${userSubquery}, '${escape(a.agent_id)}', '${escape(a.name)}')`
  ).join(', ');
  upsertQuery = `INSERT INTO agents (user_id, elevenlabs_agent_id, agent_name) VALUES ${rows} ON DUPLICATE KEY UPDATE agent_name = VALUES(agent_name)`;
}

return [{ json: { deleteQuery, upsertQuery, telegramId, agentCount: agents.length } }];

